import{_ as a,o as t,c as s,j as e,a as n,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"业力","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/杂项/业力.md","filePath":"4.资源分区/6.技艺及称号/杂项/业力.md"}'),d={name:"4.资源分区/6.技艺及称号/杂项/业力.md"};function p(_,r,l,i,b,c){return t(),s("div",null,[...r[0]||(r[0]=[e("h1",{id:"业力",tabindex:"-1"},[n("业力 "),e("a",{class:"header-anchor",href:"#业力","aria-label":'Permalink to "业力"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：灵魂蓝调011")])])],-1),o('<p>业力<br> A+8000<br> 业力，其善性恶性，必感苦乐之果，故谓之业因。其在过去者，谓为宿业，者谓为现业。俱舍光记十三曰：“造作，名业。” 在印度教中，业力是解释邪恶问题的主要方向，凡是有因果之事，均会产生业。<br> 业力只会在战斗场景中生效。所有敌对单位对友方单位（包括自身）造成伤害时，每造成3点伤害，就立即积攒1层“业”，并根据敌人的行动再参考下表为其积攒“业”</p><p>使用了1点快速医疗（及以上） 1点快速医疗/1层业<br> 进行了整轮动作攻击 2层业<br> 进行了格挡/招架/全力防御 1层业<br> 进行了移动/杂技动作移动 1层业<br> 杀死了某名友方角色 18层业<br> 激活了1点吸血（及以上） 1点吸血/1层业<br> 使用了某等级招式 每个招式/D3C6…S15层业</p><p>同时，你对场景中的敌对目标进行攻击时，还会给予其等同于造成伤害/3的业层数，当一名携带业的角色死亡时，他身上携带的业平均分给场景中剩余存活的敌对目标。当你对具有业的目标进行攻击时，可以选择并无视其至多等同于业层数/3点某类型防御，可选择多种防御，但无视的防御点总数不能高于上限。<br> 业力最多只会积攒108层，当某目标具有108层业时，你对其的下一次攻击若成功造成伤害，则视为附带S级命运来源的即死效果。</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',5)])])}const m=a(d,[["render",p]]);export{f as __pageData,m as default};
